// Cada mensagem traz msg.topic = nome da tag, msg.payload = valor
var plc = flow.get('plc') || {};
if (msg.topic) {
    plc[msg.topic] = msg.payload;
    flow.set('plc', plc);
    flow.set('plc_ok', true);
    node.status({fill:'green', shape:'dot', text: msg.topic + ' = ' + msg.payload});
}
return null;

flow.set('plc', {
    iSV_GLP_Closed:true, iSV_GLP_Opened:false,
    iSV_01_Closed:true,  iSV_01_Opened:false,
    iSV_02_Closed:true,  iSV_02_Opened:false,
    iCx_Vento_Closed:true, iCx_Vento_Opened:false,
    iZS_Queimador_Piloto:false, iZS_Queimador_Principal:false,
    iZS_Emerg:false, iZS_Soprador:false,
    iPiloto_Pronto:false, iDefeito_Bool:false, iFimDeCurso_Posicao:false,
    EMERGENCIA_ALARME1:false,
    Inicio_HMI:false, Reset_IHM:false, Reset_Seq:false,
    Inicia_Queima:false, Final_Queima:false, Teste_IHM:false, Teste_Iniciado:false,
    SV_01_DuasSaidas:false, SV_02_DuasSaidas:false,
    AUX_A_SV_02:false, AUX_F_SV_02:false, Selo_TempoSinterizacao:false,
    oAciona_Ignicao:false, oAciona_Soprador:false, oPiloto_Acesso:false,
    oSV_01_Abrir:false, oSV_01_Fechar:true,
    oSV_02_Abrir:false, oSV_02_Fechar:true,
    oGLP_Piloto_Abrir:false, oGLP_Principal_Abrir:false, oGLP_Fechada:true,
    oCx_Vento_Out:false, oReset_Rele:false,
    iTIT_01_Refratario_PV:25.0, iTIT_02_Ignicao_PV:25.0, iTIT_03_Cx_Vento_PV:25.0,
    iFIT_01_GLP_PV:0.0, iFIT_01_GLP_Val:0.0, iFIT_02_Ar_PV:0.0,
    iPIT_01_GLP_PV:0.0, iPIT_02_Gases_PV:0.0,
    Parcial_TempoSinterizacao:0.0, Min_TempoSinterizacao:120.0,
    Min_TempoResfriamento:60.0, Temp_CxVento_Max:900.0,
});
flow.set('estado', 'IDLE');
flow.set('step', 0);
flow.set('timer', 0);
flow.set('log', []);
flow.set('plc_ok', false);
node.status({fill:'green', shape:'ring', text:'Context OK'});
return null;

var plc   = flow.get('plc')   || {};
var est   = flow.get('estado') || 'IDLE';
var step  = flow.get('step')   || 0;
var timer = flow.get('timer')  || 0;
var log   = flow.get('log')    || [];

function lg(m) {
    var t = new Date().toLocaleTimeString('pt-BR');
    log.unshift('[' + t + '] ' + m);
    if (log.length > 40) log.pop();
}

// ── Simula feedbacks físicos (o simulador cpppo não tem lógica, 
//    então o Node-RED simula as respostas dos sensores) ──────────
function simFeedback() {
    // Caixa de vento
    if (plc.oCx_Vento_Out && !plc.iCx_Vento_Opened && timer >= 3) {
        plc.iCx_Vento_Opened = true; plc.iCx_Vento_Closed = false; plc.iZS_Soprador = true;
    }
    if (!plc.oCx_Vento_Out) {
        plc.iCx_Vento_Opened = false; plc.iCx_Vento_Closed = true; plc.iZS_Soprador = false;
    }
    // GLP geral
    if (!plc.oGLP_Fechada && !plc.iSV_GLP_Opened && timer >= 2) {
        plc.iSV_GLP_Opened = true; plc.iSV_GLP_Closed = false;
        plc.iPIT_01_GLP_PV = 1.5 + Math.random()*0.3;
    }
    if (plc.oGLP_Fechada) {
        plc.iSV_GLP_Opened = false; plc.iSV_GLP_Closed = true; plc.iPIT_01_GLP_PV = 0;
    }
    // SV-01
    if (plc.oSV_01_Abrir && !plc.iSV_01_Opened && timer >= 2) {
        plc.iSV_01_Opened = true; plc.iSV_01_Closed = false;
        plc.iFIT_01_GLP_PV = 5 + Math.random()*1.2;
    }
    if (!plc.oSV_01_Abrir && plc.oSV_01_Fechar) {
        plc.iSV_01_Opened = false; plc.iSV_01_Closed = true; plc.iFIT_01_GLP_PV = 0;
    }
    // SV-02
    if (plc.oSV_02_Abrir && !plc.iSV_02_Opened && timer >= 2) {
        plc.iSV_02_Opened = true; plc.iSV_02_Closed = false;
        plc.iFIT_02_Ar_PV = 25 + Math.random()*5;
    }
    if (!plc.oSV_02_Abrir && plc.oSV_02_Fechar) {
        plc.iSV_02_Opened = false; plc.iSV_02_Closed = true; plc.iFIT_02_Ar_PV = 0;
    }
}

simFeedback();

switch(est) {

  case 'IDLE':
    if (plc.Inicio_HMI || plc.Inicia_Queima) {
      if (plc.iDefeito_Bool || plc.EMERGENCIA_ALARME1) {
        lg('BLOQUEADO: Defeito/Alarme ativo. Faça RESET primeiro.');
        break;
      }
      est = 'PRE_PURGA'; step = 0; timer = 0;
      plc.Inicio_HMI = false;
      lg('INÍCIO: Sequência de queima piloto iniciada');
    }
    break;

  case 'PRE_PURGA':
    if (step === 0) {
      plc.oAciona_Soprador = true;
      plc.oCx_Vento_Out    = true;
      plc.oSV_01_Abrir = false; plc.oSV_01_Fechar = true;
      plc.oSV_02_Abrir = false; plc.oSV_02_Fechar = true;
      plc.oGLP_Fechada = true;
      lg('PURGA: Acionando soprador + abrindo caixa de vento...');
      step = 1; timer = 0;
    } else if (step === 1) {
      timer++;
      if (plc.iCx_Vento_Opened && plc.iZS_Soprador) {
        lg('PURGA: Soprador OK. Purgando 15s...');
        step = 2; timer = 0;
      } else if (timer > 12) {
        lg('FALHA: Timeout - caixa de vento não confirmada!');
        plc.EMERGENCIA_ALARME1 = true; est = 'FALHA';
      }
    } else if (step === 2) {
      timer++;
      if (timer % 5 === 0) lg('PURGA: ' + timer + '/15s...');
      if (timer >= 15) {
        lg('PURGA concluída. Abrindo GLP...');
        est = 'ABRE_GLP'; step = 0; timer = 0;
      }
    }
    break;

  case 'ABRE_GLP':
    if (step === 0) {
      plc.oGLP_Fechada = false;
      lg('GLP: Abrindo válvula geral...');
      step = 1; timer = 0;
    } else {
      timer++;
      if (plc.iSV_GLP_Opened) {
        lg('GLP: Confirmada. PIT-01=' + (plc.iPIT_01_GLP_PV||0).toFixed(2) + ' bar');
        est = 'ABRE_SV01'; step = 0; timer = 0;
      } else if (timer > 10) {
        lg('FALHA: Timeout abertura SV GLP geral!');
        plc.EMERGENCIA_ALARME1 = true; est = 'FALHA';
      }
    }
    break;

  case 'ABRE_SV01':
    if (step === 0) {
      plc.oSV_01_Abrir = true; plc.oSV_01_Fechar = false;
      plc.oGLP_Piloto_Abrir = true;
      lg('SV-01: Abrindo válvula piloto GLP...');
      step = 1; timer = 0;
    } else {
      timer++;
      if (plc.iSV_01_Opened) {
        plc.SV_01_DuasSaidas = true;
        lg('SV-01: Aberta. FIT-01=' + (plc.iFIT_01_GLP_PV||0).toFixed(1) + ' Nm³/h');
        est = 'IGNICAO'; step = 0; timer = 0;
      } else if (timer > 10) {
        lg('FALHA: Timeout SV-01!');
        plc.EMERGENCIA_ALARME1 = true; est = 'FALHA';
      }
    }
    break;

  case 'IGNICAO':
    if (step === 0) {
      plc.oAciona_Ignicao = true; plc.oPiloto_Acesso = true;
      lg('IGNIÇÃO: Ativando transformador...');
      step = 1; timer = 0;
    } else {
      timer++;
      if (timer >= 4) {
        if (Math.random() > 0.08) {  // 92% de sucesso
          plc.iZS_Queimador_Piloto = true;
          plc.iTIT_02_Ignicao_PV = 120 + Math.random()*40;
          plc.oAciona_Ignicao = false;
          lg('IGNIÇÃO: ✓ CHAMA PILOTO! Temp=' + plc.iTIT_02_Ignicao_PV.toFixed(0) + '°C');
          est = 'PILOTO_ESTAVEL'; step = 0; timer = 0;
        } else {
          plc.oAciona_Ignicao = false;
          plc.oSV_01_Abrir = false; plc.oSV_01_Fechar = true;
          plc.oGLP_Piloto_Abrir = false;
          lg('IGNIÇÃO: ✗ FALHA - Sem chama! Emergência!');
          plc.EMERGENCIA_ALARME1 = true; est = 'FALHA';
        }
      }
    }
    break;

  case 'PILOTO_ESTAVEL':
    timer++;
    plc.iTIT_01_Refratario_PV = Math.min((plc.iTIT_01_Refratario_PV||25) + 2 + Math.random()*1.5, 350);
    plc.iTIT_02_Ignicao_PV    = 140 + Math.random()*25;
    if (timer % 10 === 0)
      lg('PILOTO: Refrat=' + plc.iTIT_01_Refratario_PV.toFixed(0) + '°C');
    if (!plc.iZS_Queimador_Piloto) {
      lg('ALARME: Perda de chama piloto!');
      plc.EMERGENCIA_ALARME1 = true; est = 'FALHA';
    }
    if (plc.iTIT_01_Refratario_PV >= 300 || plc.Teste_IHM) {
      plc.Teste_IHM = false;
      lg('PILOTO: Refrat pronto (' + plc.iTIT_01_Refratario_PV.toFixed(0) + '°C). Abrindo principal...');
      est = 'ABRE_SV02'; step = 0; timer = 0;
    }
    break;

  case 'ABRE_SV02':
    if (step === 0) {
      plc.oSV_02_Abrir = true; plc.oSV_02_Fechar = false;
      plc.oGLP_Principal_Abrir = true; plc.AUX_A_SV_02 = true;
      lg('PRINCIPAL: Abrindo SV-02...');
      step = 1; timer = 0;
    } else {
      timer++;
      if (plc.iSV_02_Opened) {
        plc.SV_02_DuasSaidas = true;
        plc.iZS_Queimador_Principal = true;
        plc.Inicia_Queima = true;
        plc.Parcial_TempoSinterizacao = 0;
        lg('PRINCIPAL: ✓ SV-02 aberta! Queima plena iniciada.');
        est = 'QUEIMA_PLENA'; step = 0; timer = 0;
      } else if (timer > 12) {
        lg('FALHA: Timeout SV-02!');
        plc.EMERGENCIA_ALARME1 = true; est = 'FALHA';
      }
    }
    break;

  case 'QUEIMA_PLENA':
    timer++;
    plc.Parcial_TempoSinterizacao = (plc.Parcial_TempoSinterizacao||0) + 1;
    plc.iTIT_01_Refratario_PV = Math.min((plc.iTIT_01_Refratario_PV||300) + 1 + Math.random()*2, 950);
    plc.iTIT_03_Cx_Vento_PV   = Math.min((plc.iTIT_03_Cx_Vento_PV||25)  + 3 + Math.random()*5, 850);
    plc.iFIT_01_GLP_PV  = 8  + Math.random()*2;
    plc.iFIT_02_Ar_PV   = 28 + Math.random()*4;
    plc.iPIT_01_GLP_PV  = 1.4 + Math.random()*0.2;
    plc.iPIT_02_Gases_PV = 0.5 + Math.random()*0.2;
    if (timer % 15 === 0)
      lg('QUEIMA: Refrat=' + plc.iTIT_01_Refratario_PV.toFixed(0) +
         '°C CxV=' + plc.iTIT_03_Cx_Vento_PV.toFixed(0) +
         '°C Tempo=' + Math.round(plc.Parcial_TempoSinterizacao) + 's');
    if (plc.iTIT_03_Cx_Vento_PV > (plc.Temp_CxVento_Max||900)) {
      lg('ALARME HH: Temp caixa de vento > ' + (plc.Temp_CxVento_Max||900) + '°C!');
      plc.EMERGENCIA_ALARME1 = true;
    }
    if (!plc.iZS_Queimador_Principal) {
      lg('ALARME: Perda de chama principal!');
      plc.EMERGENCIA_ALARME1 = true; est = 'FALHA';
    }
    if (plc.Final_Queima || plc.Parcial_TempoSinterizacao >= (plc.Min_TempoSinterizacao||120)) {
      plc.Selo_TempoSinterizacao = true;
      lg('QUEIMA: Tempo OK. Iniciando desligamento...');
      est = 'DESLIGAMENTO'; step = 0; timer = 0;
    }
    break;

  case 'DESLIGAMENTO':
    if (step === 0) {
      plc.oSV_02_Abrir = false; plc.oSV_02_Fechar = true;
      plc.oGLP_Principal_Abrir = false; plc.AUX_F_SV_02 = true;
      lg('DESLIG: Fechando SV-02...');
      step = 1; timer = 0;
    } else if (step === 1) {
      timer++;
      if (plc.iSV_02_Closed || timer > 6) {
        plc.iZS_Queimador_Principal = false; plc.Inicia_Queima = false;
        lg('DESLIG: SV-02 fechada. Fechando piloto...');
        step = 2; timer = 0;
      }
    } else if (step === 2) {
      timer++;
      if (timer >= 3) {
        plc.oSV_01_Abrir = false; plc.oSV_01_Fechar = true;
        plc.oGLP_Piloto_Abrir = false; plc.oAciona_Ignicao = false;
        step = 3; timer = 0;
        lg('DESLIG: Piloto desligado. Fechando GLP geral...');
      }
    } else if (step === 3) {
      timer++;
      if (plc.iSV_01_Closed || timer > 6) {
        plc.oGLP_Fechada = true; plc.iZS_Queimador_Piloto = false;
        plc.iSV_GLP_Opened = false; plc.iSV_GLP_Closed = true;
        lg('DESLIG: GLP fechado. Resfriamento ' + (plc.Min_TempoResfriamento||60) + 's...');
        est = 'RESFRIAMENTO'; step = 0; timer = 0;
      }
    }
    break;

  case 'RESFRIAMENTO':
    timer++;
    plc.iTIT_01_Refratario_PV = Math.max((plc.iTIT_01_Refratario_PV||25) - 4 - Math.random()*2, 25);
    plc.iTIT_03_Cx_Vento_PV   = Math.max((plc.iTIT_03_Cx_Vento_PV||25)  - 6 - Math.random()*3, 25);
    if (timer % 10 === 0)
      lg('RESFRIAMENTO: ' + timer + 's | Refrat=' + plc.iTIT_01_Refratario_PV.toFixed(0) + '°C');
    if (timer >= (plc.Min_TempoResfriamento||60)) {
      plc.oAciona_Soprador = false; plc.oCx_Vento_Out = false;
      plc.iFIT_01_GLP_PV = 0; plc.iFIT_02_Ar_PV = 0;
      plc.iPIT_01_GLP_PV = 0; plc.iPIT_02_Gases_PV = 0;
      plc.Final_Queima = false; plc.Inicio_HMI = false;
      lg('RESFRIAMENTO completo. Sistema em IDLE.');
      est = 'IDLE'; step = 0; timer = 0;
    }
    break;

  case 'FALHA':
    if (plc.Reset_IHM || plc.Reset_Seq) {
      lg('RESET: Reconhecido. Voltando ao IDLE...');
      plc.oAciona_Ignicao = false; plc.oAciona_Soprador = false;
      plc.oSV_01_Abrir = false; plc.oSV_01_Fechar = true;
      plc.oSV_02_Abrir = false; plc.oSV_02_Fechar = true;
      plc.oGLP_Piloto_Abrir = false; plc.oGLP_Principal_Abrir = false;
      plc.oGLP_Fechada = true; plc.oCx_Vento_Out = false;
      plc.iZS_Queimador_Piloto = false; plc.iZS_Queimador_Principal = false;
      plc.EMERGENCIA_ALARME1 = false; plc.iDefeito_Bool = false;
      plc.Inicia_Queima = false; plc.Inicio_HMI = false;
      plc.Reset_IHM = false; plc.Reset_Seq = false;
      est = 'IDLE'; step = 0; timer = 0;
    }
    break;
}

flow.set('plc', plc);
flow.set('estado', est);
flow.set('step', step);
flow.set('timer', timer);
flow.set('log', log);

return [{payload: {plc: plc, estado: est, log: log}}];

var plc = msg.payload.plc;
node.send({payload: plc['Inicio_HMI']});
node.send(null, {payload: plc['Reset_IHM']});
node.send(null, null, {payload: plc['Reset_Seq']});
node.send(null, null, null, {payload: plc['Final_Queima']});
node.send(null, null, null, null, {payload: plc['Teste_IHM']});
node.send(null, null, null, null, null, {payload: plc['EMERGENCIA_ALARME1']});
node.send(null, null, null, null, null, null, {payload: plc['oAciona_Ignicao']});
node.send(null, null, null, null, null, null, null, {payload: plc['oAciona_Soprador']});
node.send(null, null, null, null, null, null, null, null, {payload: plc['oPiloto_Acesso']});
node.send(null, null, null, null, null, null, null, null, null, {payload: plc['oSV_01_Abrir']});
