node.send(null, null, null, null, null, null, null, null, null, null, null, {payload: plc['oSV_02_Abrir']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['oSV_02_Fechar']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['oGLP_Piloto_Abrir']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['oGLP_Principal_Abrir']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['oGLP_Fechada']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['oCx_Vento_Out']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['oReset_Rele']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['SV_01_DuasSaidas']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['SV_02_DuasSaidas']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['AUX_A_SV_02']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['AUX_F_SV_02']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['Selo_TempoSinterizacao']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['Inicia_Queima']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['iTIT_01_Refratario_PV']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['iTIT_02_Ignicao_PV']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['iTIT_03_Cx_Vento_PV']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['iFIT_01_GLP_PV']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['iFIT_02_Ar_PV']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['iPIT_01_GLP_PV']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['iPIT_02_Gases_PV']});
node.send(null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, {payload: plc['Parcial_TempoSinterizacao']});
return null;

var plc = flow.get('plc') || {};
switch(msg.payload) {
  case 'iniciar':    plc.Inicio_HMI = true; break;
  case 'finalizar':  plc.Final_Queima = true; break;
  case 'reset':      plc.Reset_IHM = true; plc.Reset_Seq = true; break;
  case 'testar':     plc.Teste_IHM = true; break;
  case 'emergencia':
    plc.EMERGENCIA_ALARME1 = true; plc.iDefeito_Bool = true; plc.iZS_Emerg = true;
    plc.oSV_01_Abrir = false; plc.oSV_01_Fechar = true;
    plc.oSV_02_Abrir = false; plc.oSV_02_Fechar = true;
    plc.oGLP_Piloto_Abrir = false; plc.oGLP_Principal_Abrir = false;
    plc.oAciona_Ignicao = false;
    flow.set('estado', 'FALHA'); flow.set('step', 0); flow.set('timer', 0);
    break;
}
flow.set('plc', plc);
node.status({fill:'blue', shape:'dot', text: msg.payload});
return null;
